import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a mortgage amortization schedule?", a: "A mortgage amortization schedule is a month-by-month table showing each payment, how much goes to principal, how much goes to interest, and the remaining balance." },
  { q: "Why does so much of early mortgage payments go to interest?", a: "Interest is calculated on the outstanding balance. Early in the loan, the balance is high, so the interest portion is larger." },
  { q: "How do extra payments affect your amortization schedule?", a: "Extra payments reduce principal faster, which lowers future interest and can shorten the payoff date." },
  { q: "How do you calculate your equity from an amortization schedule?", a: "Equity is estimated as the home value minus the remaining mortgage balance. If home value changes, equity changes too." },
  { q: "What is negative amortization?", a: "Negative amortization happens when payments are not enough to cover interest, so unpaid interest is added to the loan balance." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function pmt(principal: number, rate: number, years: number) { const r = rate / 100 / 12; const n = years * 12; return r === 0 ? principal / n : principal * r / (1 - Math.pow(1 + r, -n)); }
function schedule(amount: number, rate: number, years: number, startDate: string, extra = 0) {
  const monthly = pmt(amount, rate, years);
  const r = rate / 100 / 12;
  let balance = amount;
  const start = new Date(`${startDate}T00:00:00`);
  const rows = [];
  for (let i = 1; i <= years * 12 && balance > 0.01; i += 1) {
    const interest = balance * r;
    const principal = Math.min(balance, monthly - interest + extra);
    const total = principal + interest;
    balance = Math.max(0, balance - principal);
    const date = new Date(start);
    date.setMonth(start.getMonth() + i - 1);
    rows.push({ number: i, date: date.toLocaleDateString("en-US", { month: "short", year: "numeric" }), principal, interest, total, balance });
  }
  return { monthly, rows };
}

export default function MortgageAmortizationCalculator() {
  useCurrencyVersion();
  const [amount, setAmount] = useState(300000);
  const [rate, setRate] = useState(6.5);
  const [years, setYears] = useState(30);
  const [startDate, setStartDate] = useState("2026-06-01");
  const [extra, setExtra] = useState(0);
  const result = useMemo(() => schedule(amount, rate, years, startDate, extra), [amount, rate, years, startDate, extra]);
  const totalInterest = result.rows.reduce((sum, r) => sum + r.interest, 0);
  const totalPrincipal = result.rows.reduce((sum, r) => sum + r.principal, 0);
  const comparison = [1, 5, 10, 15, 20, 25, 30].map((year) => {
    const rows = schedule(300000, 6.5, 30, "2026-06-01").rows.slice(0, year * 12);
    const principal = rows.reduce((s, r) => s + r.principal, 0);
    const interest = rows.reduce((s, r) => s + r.interest, 0);
    const balance = rows[rows.length - 1]?.balance || 0;
    return { year, principal, interest, total: principal + interest, balance, equity: (300000 - balance) / 300000 * 100 };
  });

  return (
    <>
      <SEOHead title="Free Mortgage Amortization Calculator Online - Calculate Full Mortgage Schedule Instantly | CalcHive" description="Free online mortgage amortization calculator. Calculate complete month-by-month mortgage amortization schedule with principal, interest and balance for any loan instantly. 100% free, no signup required." canonical="/mortgage-amortization-calculator" keywords="free mortgage amortization calculator, mortgage amortization schedule calculator free, home loan amortization calculator free online, calculate mortgage amortization free, monthly mortgage breakdown calculator free" category="Financial Calculators" breadcrumbName="Free Mortgage Amortization Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Mortgage Amortization Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Build a month-by-month mortgage amortization schedule with optional extra payments.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Mortgage amount</label><input type="number" value={amount} onChange={(e) => setAmount(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Loan term years</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Start date</label><input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Extra monthly payment</label><input type="number" value={extra} onChange={(e) => setExtra(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.monthly)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest</p><p className="text-lg font-extrabold text-foreground">{money(totalInterest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total principal</p><p className="text-lg font-extrabold text-foreground">{money(totalPrincipal)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Payoff payments</p><p className="text-lg font-extrabold text-foreground">{result.rows.length}</p></div></div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate a Full Mortgage Amortization Schedule for Free</h2><p className="text-muted-foreground leading-relaxed">Each month, interest is calculated from the remaining balance. The rest of the payment reduces principal, and extra payments reduce principal even faster.</p><h2 className="text-2xl font-bold text-foreground">How to Read and Understand Your Mortgage Amortization Table</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Mortgage Amortization Summary - $300,000 at 6.5% 30yr</caption><thead className="bg-muted/60"><tr>{["Year", "Principal Paid", "Interest Paid", "Total Paid", "Remaining Balance", "Equity %"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((r) => <tr key={r.year}><td className="py-2.5 px-3 font-semibold">{r.year}</td><td className="py-2.5 px-3">{money(r.principal)}</td><td className="py-2.5 px-3">{money(r.interest)}</td><td className="py-2.5 px-3">{money(r.total)}</td><td className="py-2.5 px-3">{money(r.balance)}</td><td className="py-2.5 px-3">{r.equity.toFixed(1)}%</td></tr>)}</tbody></table></div><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Monthly Amortization Schedule</caption><thead className="bg-muted/60"><tr>{["Date", "Payment #", "Principal", "Interest", "Total Payment", "Remaining Balance"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.rows.slice(0, 360).map((r) => <tr key={r.number}><td className="py-2.5 px-3">{r.date}</td><td className="py-2.5 px-3 font-semibold">{r.number}</td><td className="py-2.5 px-3">{money(r.principal)}</td><td className="py-2.5 px-3">{money(r.interest)}</td><td className="py-2.5 px-3">{money(r.total)}</td><td className="py-2.5 px-3">{money(r.balance)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Home Loan Amortization Tool for Homeowners</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/mortgage-amortization-calculator" headingLevel="h3" /></main>
    </>
  );
}


